
import { useNavigate } from 'react-router-dom';

import './Hero.css';


function Hero() {
    const navigate = useNavigate();
    const handleButtonClick = () => {
        navigate('/');
        window.scrollTo({
            top: 0,
            behavior: 'smooth'
        });
    };

    return (
        <section className="hero">
            <h1>Welcome to Guo Hua Chen and his family home.</h1>
            <p> We have collected all information and photos and videos as evidence and  in order to fight against unfair treatments and discrimination to win the justice</p>
            <button className="btn" onClick={handleButtonClick}>Get Started</button>


        </section>
    );
}

export default Hero;