
import { useParams } from 'react-router-dom';
import ProgrammingMyfamily from "./ProgrammingMyfamily";

function UserProfile() {
    const { userId } = useParams();

    return (
        <div style={{ padding: '2rem', textAlign: 'left' }}>
            <h1>Who am I?</h1>
            <p>Viewing my profile introduction: <strong>{userId}</strong></p>

            <div style={{
                background: '#f8f9fa',
                padding: '2rem',
                borderRadius: '8px',
                marginTop: '2rem',
                maxWidth: '400px',
                margin: '2rem auto'
            }}>
                <h2>Myself and my family living in a most discriminated community in NYC, and I am a houseowner.</h2>
                <p>Name: Guo Hua Chen, or Edward Chen, a Chinese immigrant</p>
                <p>career:A Sr Web developer, computer programmer, graphic designer, and a painter</p>
                <p>Language: Cantonese, Manderin, English</p>
            </div>

            <ProgrammingMyfamily />
        </div>
    );
}

export default UserProfile;