import React, { useState } from 'react';
import YouTubePlayer from './displayUtubeembed';
import './Programming.css';
import { useNavigate } from 'react-router-dom';
import Button from 'react-bootstrap/Button';
import 'bootstrap/dist/css/bootstrap.min.css';
import Badge from 'react-bootstrap/Badge';


const Programminggroup = () => {

    const navigate = useNavigate();
    const handleButtonClickHOA = () => {
        navigate('/ProgrammingHOA');
        window.scrollTo({
            top: 280,
            behavior: 'smooth'
        });
    };
    const handleButtonClicklynn = () => {
        navigate('/Programminglynn');
        window.scrollTo({
            top: 280,
            behavior: 'smooth'
        });
    };
    const handleButtonClickQin = () => {
        navigate('/ProgrammingQin');
        window.scrollTo({
            top: 280,
            behavior: 'smooth'
        });
    };
    const handleButtonClickMyfamily = () => {
        navigate('/ProgrammingMyfamily');
        window.scrollTo({
            top: 280,
            behavior: 'smooth'
        });
    };
    const handleButtonClickSpecial = () => {
        navigate('/ProgrammingSpecial');
        window.scrollTo({
            top: 280,
            behavior: 'smooth'
        });
    };
    return (
        <div>

            <ul><li>   <Badge as="Button" variant="success" className="btn" onClick={handleButtonClickHOA}>Complaints against HOA</Badge></li>
                <li>   <Badge as="Button" variant="success" className="btn" onClick={handleButtonClicklynn}>Complaints Lynn</Badge></li>
                <li>   <Badge as="Button" variant="success" className="btn" onClick={handleButtonClickQin}>Complaints HOA's president</Badge></li>
                <li>   <Badge as="Button" variant="success" className="btn" onClick={handleButtonClickMyfamily}>My family</Badge></li>
                <li>   <Badge as="Button" variant="success" className="btn" onClick={handleButtonClickSpecial}>Special Section</Badge></li>
            </ul>
        </div>
    );
};


export default Programminggroup;

