
import React from 'react';

const ImageGallery = ({ images }) => {
    return (
        <div style={{ display: 'flex', gap: '16px', flexWrap: 'wrap' }}>
            {images.map((img, index) => (
                <img
                    key={index}
                    src={img.src}
                    alt={img.alt}
                    style={{ width: '1200px', height: 'auto', borderRadius: '8px' }}
                />
            ))}
        </div>
    );
};

export default ImageGallery;