export default function PDFSelector() {
    const [selectedPdf, setSelectedPdf] = useState(pdfList[0].url);

    return (
        <>
            <select onChange={(e) => setSelectedPdf(e.target.value)}>
                {pdfList.map((pdf) => (
                    <option key={pdf.url} value={pdf.url}>
                        {pdf.name}
                    </option>
                ))}
            </select>
            <PDFViewer fileUrl={selectedPdf} />
        </>
    );
}