import { Link, useLocation } from 'react-router-dom';


const Navigation = () => {
    const location = useLocation()
    const handleButtonClickToTop = () => {
        window.scrollTo({
            top: 200,
            behavior: 'smooth'
        });
    }
    return (

        <nav style={{
            padding: '1rem',
            background: '#378becff',
            color: 'white',


        }} className="navbar nav-container">
            <div style={{
                maxWidth: '100%',
                margin: '0 auto',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between'
            }}>


                <div style={{ display: 'flex', gap: '10px', flexWrap: "wrap", maxWidth: '100%' }}>

                    <Link
                        to="./"
                        style={{
                            color: location.pathname === '/' ? '#eb5587ff' : 'white',
                            textDecoration: 'none',
                            fontWeight: location.pathname === '/' ? 'bold' : 'normal'
                        }} onClick={handleButtonClickToTop} className="p-2"
                    >
                        Home
                    </Link>

                    <Link
                        to="./About"
                        style={{
                            color: location.pathname === '/About' ? '#47db34ff' : 'white',
                            textDecoration: 'none',
                            fontWeight: location.pathname === '/About' ? 'bold' : 'normal'
                        }} onClick={handleButtonClickToTop} className="p-2"
                    >
                        About
                    </Link>


                    <Link
                        to="./Contact"
                        style={{
                            color: location.pathname === '/Contact' ? '#47db34ff' : 'white',
                            textDecoration: 'none',
                            fontWeight: location.pathname === '/Contact' ? 'bold' : 'normal'
                        }} onClick={handleButtonClickToTop} className="p-2"
                    >
                        Contact
                    </Link>

                    <Link
                        to="./user/Guo Hua Chen"
                        style={{
                            color: location.pathname.includes('/user') ? '#47db34ff' : 'white',
                            textDecoration: 'none',
                            fontWeight: location.pathname.includes('/user') ? 'bold' : 'normal'
                        }} onClick={handleButtonClickToTop} className="p-2"
                    >
                        My Profile
                    </Link>
                    <Link
                        to="./AppDemos"
                        style={{
                            color: location.pathname.includes('/AppDemos') ? '#47db34ff' : 'white',
                            textDecoration: 'none',
                            fontWeight: location.pathname.includes('/AppDemos') ? 'bold' : 'normal'
                        }} onClick={handleButtonClickToTop} className="p-2"
                    >
                        HOA violation Issues
                    </Link>
                    <Link
                        to="./Email"
                        style={{
                            color: location.pathname.includes('/Email') ? '#47db34ff' : 'white',
                            textDecoration: 'none',
                            fontWeight: location.pathname.includes('/Email') ? 'bold' : 'normal'
                        }} onClick={handleButtonClickToTop} className="p-2"
                    >
                        Emails to HOA(Abtsthe Dunes)
                    </Link>
                    <Link
                        to="./Developments"
                        style={{
                            color: location.pathname.includes('/Developments') ? '#47db34ff' : 'white',
                            textDecoration: 'none',
                            fontWeight: location.pathname.includes('/Developments') ? 'bold' : 'normal'
                        }} onClick={handleButtonClickToTop} className="p-2"
                    >
                        Evidence photos
                    </Link>

                    <Link
                        to="./Programming"
                        style={{
                            color: location.pathname.includes('/Programming') ? '#47db34ff' : 'white',
                            textDecoration: 'none',
                            fontWeight: location.pathname.includes('/Programming') ? 'bold' : 'normal'
                        }} onClick={handleButtonClickToTop} className="p-2"
                    >
                        Evidence Videos
                    </Link>



                </div>
            </div>
        </nav>

    )
}

export default Navigation;